SET del_yn = 'Y',
del_ts = NOW(),
del_by = #{userId}
WHERE dev_prj_id = #{dev_prj_id}

UPDATE tb_dev_rate_info
SET del_yn = 'Y',
del_ts = NOW(),
del_by = #{userId}
WHERE dev_prj_id = #{dev_prj_id}
AND dev_id = #{dev_id}

mapper.select:
SELECT cd, cd_nm, IFNULL(adinfo_01, 'N') AS inprj_yn FROM tb_cd_mst WHERE del_yn = 'N' AND use_yn = 'Y' AND grp_yn = 'N' AND grp_cd = #{grp_cd}
AND (cd LIKE CONCAT('%', #{keyword}, '%') OR cd_nm LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY sort_no ASC, cd ASC

mapper.insert:
INSERT INTO tb_cd_mst (
    grp_cd, cd, cd_nm, grp_yn, sort_no, use_yn, del_yn,
    adinfo_01, crt_ts, crt_by, upd_ts, upd_by
) VALUES (
    #{grp_cd}, #{cd}, #{cd_nm}, 'N',
    (SELECT IFNULL(MAX(sort_no), 0) + 1 FROM tb_cd_mst t WHERE t.grp_cd = #{grp_cd}),
    'Y', 'N',
    #{inprj_yn}, NOW(), #{userId}, NOW(), #{userId}
)
